   361	        // Arrange: Application context ensures SetFocus works through nested hierarchy.
   362	        VirtualTimeProvider time = new ();
   363	
   364	        using IApplication app = Application.Create (time);
   365	        app.Init (DriverRegistry.Names.ANSI);
   366	        IRunnable runnable = new Runnable ();
   367	
   368	        // ancestor opts in to Activate bubbling and contains the OptionSelector.
   369	        // CanFocus = true is required so the focus chain can propagate through ancestor.
   370	        View ancestor = new () { Id = "ancestor", CanFocus = true };
   371	        ancestor.CommandsToBubbleUp = [Command.Activate];
   372	
   373	        OptionSelector optionSelector = new ();
   374	        optionSelector.Labels = ["Option1", "Option2"];
   375	        ancestor.Add (optionSelector);
