   381	
   382	        // Focus Option2 so Activate dispatches to it.
   383	        CheckBox option2 = optionSelector.SubViews.OfType<CheckBox> ().First (cb => cb.Title == "Option2");
   384	        option2.HasFocus = true;
   385	        Assert.True (option2.HasFocus);
   386	
